/* eslint-disable jsx-a11y/click-events-have-key-events */
/* eslint-disable jsx-a11y/no-static-element-interactions */
/* eslint-disable react/jsx-no-bind */
import { css } from '@emotion/core';
import {
  ButtonLink,
  ButtonSizes,
  ButtonVariants,
  Icon,
  IconSizes,
  P,
  Typography,
} from 'components';
import { colors, icons, media, typography } from 'core';
import React, { FC, useState } from 'react';

import { Circle } from './library/Circle';
import { DropdownHeader } from './library/DropdownHeader';
import { Props } from './props';

export const Dropdown: FC<Props> = () => {
  const [open, setOpen] = useState(false);
  const [onHover, setOnHover] = useState(false);
  return (
    <DropdownHeader
      className="d-flex flex-column justify-content-between align-items-center"
      onMouseOver={() => setOnHover(true)}
      onMouseLeave={() => setOnHover(false)}
      open={open}
      onHover={onHover}
    >
      <div
        onClick={() => setOpen(!open)}
        className="d-flex justify-content-between align-items-center w-100"
        css={css`
          cursor: pointer;
        `}
      >
        <div className="d-flex align-items-center">
          <Circle />
          <div className="pl-3">
            <Typography
              as="h2"
              css={css(
                typography.styles.headingSemiBold17,
                media.queryStyled([
                  typography.styles.headingSemiBold17,
                  typography.styles.headingSemiBold17,
                  typography.styles.headingBold22,
                ]),
              )}
            >
              Что делать при наличии сопутствующих заболеваний?
            </Typography>
          </div>
        </div>
        <div>
          {open ? (
            <Icon icon={icons.arrows.keyboardArrowUp} size={IconSizes.Medium} />
          ) : (
            <Icon icon={icons.arrows.keyboardArrowDown} size={IconSizes.Medium} />
          )}
        </div>
      </div>
      {open && (
        <div className="pt-4">
          <P>
            Люди с сопутствующими заболеваниями могут получить вакцины от COVID-19, разрешенные FDA.
            Фактически, вакцинация особенно важна для взрослых любого возраста с определенными
            сопутствующими заболеваниями, такими как диабет и высокое артериальное давление,
            поскольку они подвержены повышенному риску тяжелого течния заболевания COVID-19. При
            возникновении вопросов обратитесь к своему врачу. Люди, страдающие аутоиммунными
            заболеваниями и с ранее диагностированным синдромом Гийена-Барре или параличом Белла,
            могут вакцинироваться от COVID-19.
          </P>
          <ButtonLink
            href="https://google.com"
            variant={ButtonVariants.Flat}
            size={ButtonSizes.Small}
            className="pt-4 pl-0"
          >
            <P
              color={colors.variants.Neutral.Grey}
              typography={typography.variants.Element.Regular12}
            >
              Как работают вакцины (vaccines.gov)
            </P>
            <Icon
              icon={icons.arrows.keyboardArrowRight}
              color={colors.variants.Neutral.Black}
              className="mr-1"
            />
          </ButtonLink>
        </div>
      )}
    </DropdownHeader>
  );
};
